116:     comptime Commands: type,
117: ) Commands {
118:     comptime assert(@typeInfo(Commands) == .@"union");
119:     comptime assert(std.meta.fields(Commands).len >= 2);
120: 
121:     const first_arg = args.next() orelse fatal(
122:         "subcommand required, expected {s}",
123:         .{comptime fields_to_comma_list(Commands)},
124:     );
125: 
126:     // NB: help must be declared as *pub* const to be visible here.
127:     if (@hasDecl(Commands, "help")) {
128:         if (std.mem.eql(u8, first_arg, "-h") or std.mem.eql(u8, first_arg, "--help")) {
129:             std.io.getStdOut().writeAll(Commands.help) catch std.process.exit(1);
130:             std.process.exit(0);
131:         }
132:     }
133: 
134:     inline for (comptime std.meta.fields(Commands)) |field| {
135:         comptime assert(std.mem.indexOfScalar(u8, field.name, '_') == null);
136:         if (std.mem.eql(u8, first_arg, field.name)) {
137:             return @unionInit(Commands, field.name, parse_flags(arena, args, field.type));
138:         }
139:     }
140:     fatal("unknown subcommand: '{s}'", .{first_arg});
141: }
142: 
143: fn parse_flags(arena: Allocator, args: *std.process.ArgIterator, comptime CLIArgs: type) CLIArgs {
144:     @setEvalBranchQuota(5_000);
145: 
146:     if (CLIArgs == void) {
147:         if (args.next()) |arg| {
148:             fatal("unexpected argument: '{s}'", .{arg});
149:         }
150:         return {};
151:     }
152: 
153:     if (@typeInfo(CLIArgs) == .@"union") {
154:         return parse_commands(arena, args, CLIArgs);
155:     }
156: 
157:     assert(@typeInfo(CLIArgs) == .@"struct");
158: 
159:     const fields = std.meta.fields(CLIArgs);
160:     comptime var fields_named, var fields_positional: []const std.builtin.Type.StructField =
161:         for (fields, 0..) |field, index| {
162:             if (std.mem.eql(u8, field.name, "--")) {
163:                 assert(field.type == void);
164:                 const positional_count = fields.len - index - 1;
165:                 if (positional_count == 0) @panic("expected positional fields");
166: 
167:                 break .{
168:                     fields[0..index].*,
169:                     fields[index + 1 ..],
170:                 };
171:             }
172:         } else .{
173:             fields[0..fields.len].*,
174:             &.{},
175:         };
176: 
177:     comptime var field_extended: ?std.builtin.Type.StructField = null;
178:     if (fields_positional.len == 1 and fields_positional[0].type == []const []const u8) {
179:         field_extended = fields_positional[0];
180:         fields_positional = fields_positional[1..];
181:         assert(fields_positional.len == 0);
182:     }
183: 
184:     var arg_extended: if (field_extended == null) void else std.ArrayListUnmanaged([]const u8) =
185:         if (field_extended == null) {} else .empty;
186: 
187:     comptime {
188:         assert(
189:             fields.len == fields_named.len +
190:                 fields_positional.len +
191:                 @intFromBool(field_extended != null) +
192:                 if (field_extended != null or fields_positional.len > 0) 1 else 0, // The @"--"
193:         );
194:         if (field_extended != null) assert(fields_positional.len == 0);
195: 
196:         // When parsing named arguments, we must consider longer arguments first, such that
197:         // `--foo-bar=92` is not confused for a misspelled `--foo=92`. Using `std.sort` for
198:         // comptime-only values does not work, so open-code insertion sort, and comptime assert
199:         // order during the actual parsing.
200:         for (fields_named[0..], 0..) |*field_right, i| {
201:             for (fields_named[0..i]) |*field_left| {
202:                 if (field_left.name.len < field_right.name.len) {
203:                     std.mem.swap(std.builtin.Type.StructField, field_left, field_right);
204:                 }
205:             }
206:         }
207: 
208:         for (fields_named) |field| {
209:             switch (@typeInfo(field.type)) {
210:                 .bool => {
211:                     // Boolean flags must have a default.
212:                     assert(field.defaultValue() != null);
213:                     assert(field.defaultValue().? == false);
214:                 },
215:                 .optional => |optional| {
216:                     // Optional flags must have a default.
217:                     assert(field.defaultValue() != null);
218:                     assert(field.defaultValue().? == null);
219: 
220:                     assert_valid_value_type(optional.child);
221:                 },
222:                 else => {
223:                     assert_valid_value_type(field.type);
224:                 },
225:             }
226:         }
227: 
228:         var optional_tail: bool = false;
229:         for (fields_positional) |field| {
230:             if (field.defaultValue() == null) {
231:                 if (optional_tail) @panic("optional positional arguments must be trailing");
232:             } else {
233:                 optional_tail = true;
234:             }
235:             switch (@typeInfo(field.type)) {
236:                 .optional => |optional| {
237:                     // optional flags should have a default
238:                     assert(field.defaultValue() != null);
239:                     assert(field.defaultValue().? == null);
240:                     assert_valid_value_type(optional.child);
241:                 },
242:                 else => {
243:                     assert_valid_value_type(field.type);
244:                 },
245:             }
246:         }
247:     }
248: 
249:     var counts: std.enums.EnumFieldStruct(std.meta.FieldEnum(CLIArgs), u32, 0) = .{};
250:     var result: CLIArgs = undefined;
251:     var parsed_positional = false;
252:     next_arg: while (args.next()) |arg| {
253:         comptime var field_len_prev = std.math.maxInt(usize);
254:         inline for (fields_named) |field| {
255:             const flag = comptime flag_name(field);
256: 
257:             comptime assert(field_len_prev >= field.name.len);
258:             field_len_prev = field.name.len;
259:             if (std.mem.startsWith(u8, arg, flag)) {
260:                 if (parsed_positional) {
261:                     fatal("unexpected trailing option: '{s}'", .{arg});
262:                 }
263: 
264:                 @field(counts, field.name) += 1;
265:                 const flag_value = parse_flag(field.type, flag, arg);
266:                 @field(result, field.name) = flag_value;
267:                 continue :next_arg;
268:             }
269:         }
270: 
271:         if (fields_positional.len > 0) {
272:             assert(field_extended == null);
273:             counts.@"--" += 1;
274:             switch (counts.@"--" - 1) {
275:                 inline 0...fields_positional.len - 1 => |field_index| {
276:                     const field = fields_positional[field_index];
277:                     const flag = comptime flag_name_positional(field);
278: 
279:                     if (arg.len == 0) fatal("{s}: empty argument", .{flag});
280:                     // Prevent ambiguity between a flag and positional argument value. We could add
281:                     // support for bare ` -- ` as a disambiguation mechanism once we have a real
282:                     // use-case.
283:                     if (arg[0] == '-') fatal("unexpected argument: '{s}'", .{arg});
284:                     parsed_positional = true;
285: 
286:                     @field(result, field.name) =
287:                         parse_value(field.type, flag, arg);
288:                     continue :next_arg;
289:                 },
290:                 else => {}, // Fall-through to the unexpected argument error.
291:             }
292:         } else {
293:             if (field_extended != null) {
294:                 if (std.mem.eql(u8, arg, "--")) {
295:                     break;
296:                 } else {
297:                     fatal("unexpected argument: '{s}'; expected '-- ...'", .{arg});
298:                 }
299:             }
300:         }
301: 
302:         fatal("unexpected argument: '{s}'", .{arg});
303:     }
304:     if (field_extended != null) {
305:         while (args.next()) |arg| {
306:             arg_extended.append(arena, arg) catch |err| oom(err);
307:         }
308:     }
309: 
310:     assert(args.next() == null);
311: 
312:     inline for (fields_named) |field| {
313:         const flag = flag_name(field);
314:         switch (@field(counts, field.name)) {
315:             0 => if (field.defaultValue()) |default| {
316:                 @field(result, field.name) = default;
317:             } else {
318:                 fatal("{s}: argument is required", .{flag});
319:             },
320:             1 => {},
321:             else => fatal("{s}: duplicate argument", .{flag}),
322:         }
323:     }
324: 
325:     if (fields_positional.len > 0) {
326:         assert(field_extended == null);
327:         assert(counts.@"--" <= fields_positional.len);
328:         inline for (fields_positional, 0..) |field, field_index| {
329:             if (field_index >= counts.@"--") {
330:                 const flag = comptime flag_name_positional(field);
331:                 if (field.defaultValue()) |default| {
332:                     @field(result, field.name) = default;
333:                 } else {
334:                     fatal("{s}: argument is required", .{flag});
335:                 }
336:             }
337:         }
338:     }
339: 
340:     if (field_extended) |field| {
341:         assert(fields_positional.len == 0);
342:         @field(result, field.name) = arg_extended.items;
343:     }
344: 
345:     return result;
346: }
