348: fn assert_valid_value_type(comptime T: type) void {
349:     comptime {
350:         if (T == []const u8 or T == [:0]const u8 or @typeInfo(T) == .int) return;
351:         if (@hasDecl(T, "parse_flag_value")) return;
352: 
353:         if (@typeInfo(T) == .@"enum") {
354:             const info = @typeInfo(T).@"enum";
355:             assert(info.is_exhaustive);
356:             assert(info.fields.len >= 2);
357:             return;
358:         }
359: 
360:         @compileError("flags: unsupported type: " ++ @typeName(T));
361:     }
362: }
363: 
364: /// Parse, e.g., `--cluster=123` into `123` integer
365: fn parse_flag(comptime T: type, flag: []const u8, arg: [:0]const u8) T {
366:     assert(flag[0] == '-' and flag[1] == '-');
367: 
368:     if (T == bool) {
369:         if (std.mem.eql(u8, arg, flag)) {
370:             // Bool argument may not have a value.
371:             return true;
372:         }
373:     }
374: 
375:     const value = parse_flag_split_value(flag, arg);
376:     assert(value.len > 0);
377:     return parse_value(T, flag, value);
378: }
379: 
380: /// Splits the value part from a `--arg=value` syntax.
381: fn parse_flag_split_value(flag: []const u8, arg: [:0]const u8) [:0]const u8 {
382:     assert(flag[0] == '-' and flag[1] == '-');
383:     assert(std.mem.startsWith(u8, arg, flag));
384: 
385:     const value = arg[flag.len..];
386:     if (value.len == 0) {
387:         fatal("{s}: expected value separator '='", .{flag});
388:     }
389:     if (value[0] != '=') {
390:         fatal(
391:             "{s}: expected value separator '=', but found '{c}' in '{s}'",
392:             .{ flag, value[0], arg },
393:         );
394:     }
395:     if (value.len == 1) fatal("{s}: argument requires a value", .{flag});
396:     return value[1..];
397: }
398: 
399: fn parse_value(comptime T: type, flag: []const u8, value: [:0]const u8) T {
400:     assert((flag[0] == '-' and flag[1] == '-') or flag[0] == '<');
401:     assert(value.len > 0);
402: 
403:     const V = switch (@typeInfo(T)) {
404:         .optional => |optional| optional.child,
405:         else => T,
406:     };
407: 
408:     if (V == []const u8 or V == [:0]const u8) return value;
409:     if (V == bool) return parse_value_bool(flag, value);
410:     if (@typeInfo(V) == .int) return parse_value_int(V, flag, value);
411:     if (@hasDecl(V, "parse_flag_value")) {
412:         // Contracts:
413:         // - Input string is guaranteed to be not empty.
414:         // - Output diagnostic must point to statically-allocated data.
415:         // - Diagnostic must start with a lower case letter.
416:         // - Diagnostic must end with a ':' (it will be concatenated with original input).
417:         // - (static_diagnostic != null) iff error.InvalidFlagValue is returned.
418:         const parse_flag_value: fn (
419:             string: []const u8,
420:             static_diagnostic: *?[]const u8,
421:         ) error{InvalidFlagValue}!V = V.parse_flag_value;
422: 
423:         var diagnostic: ?[]const u8 = null;
424:         if (parse_flag_value(value, &diagnostic)) |result| {
425:             assert(diagnostic == null);
426:             return result;
427:         } else |err| switch (err) {
428:             error.InvalidFlagValue => {
429:                 const message = diagnostic.?;
430:                 assert(std.ascii.isLower(message[0]));
431:                 assert(message[message.len - 1] == ':');
432:                 fatal("{s}: {s} '{s}'", .{ flag, message, value });
433:             },
434:         }
435:     }
436:     if (@typeInfo(V) == .@"enum") return parse_value_enum(V, flag, value);
437:     comptime unreachable;
438: }
439: 
440: /// Parse string value into an integer, providing a nice error message for the user.
441: fn parse_value_int(comptime T: type, flag: []const u8, value: [:0]const u8) T {
442:     assert((flag[0] == '-' and flag[1] == '-') or flag[0] == '<');
443: 
444:     // Support only unsigned integers, as a conservative choice.
445:     comptime assert(@typeInfo(T).int.signedness == .unsigned);
446:     return std.fmt.parseUnsigned(T, value, 10) catch |err| {
447:         switch (err) {
448:             error.Overflow => fatal(
449:                 "{s}: value exceeds {d}-bit {s} integer: '{s}'",
450:                 .{ flag, @typeInfo(T).int.bits, @tagName(@typeInfo(T).int.signedness), value },
451:             ),
452:             error.InvalidCharacter => fatal(
453:                 "{s}: expected an integer value, but found '{s}' (invalid digit)",
454:                 .{ flag, value },
455:             ),
456:         }
457:     };
458: }
459: 
460: fn parse_value_bool(flag: []const u8, value: [:0]const u8) bool {
461:     return switch (parse_value_enum(
462:         enum {
463:             true,
464:             false,
465:         },
466:         flag,
467:         value,
468:     )) {
469:         .true => true,
470:         .false => false,
471:     };
472: }
473: 
474: fn parse_value_enum(comptime E: type, flag: []const u8, value: [:0]const u8) E {
475:     assert((flag[0] == '-' and flag[1] == '-') or flag[0] == '<');
476:     comptime assert(@typeInfo(E).@"enum".is_exhaustive);
477: 
478:     return std.meta.stringToEnum(E, value) orelse fatal(
479:         "{s}: expected one of {s}, but found '{s}'",
480:         .{ flag, comptime fields_to_comma_list(E), value },
481:     );
482: }
483: 
484: fn fields_to_comma_list(comptime E: type) []const u8 {
485:     comptime {
486:         const field_count = std.meta.fields(E).len;
487:         assert(field_count >= 2);
488: 
489:         var result: []const u8 = "";
490:         for (std.meta.fields(E), 0..) |field, field_index| {
491:             const separator = switch (field_index) {
492:                 0 => "",
493:                 else => ", ",
494:                 field_count - 1 => if (field_count == 2) " or " else ", or ",
495:             };
496:             result = result ++ separator ++ "'" ++ field.name ++ "'";
497:         }
498:         return result;
499:     }
500: }
501: 
502: fn flag_name(comptime field: std.builtin.Type.StructField) []const u8 {
503:     return comptime blk: {
504:         assert(!std.mem.eql(u8, field.name, "-"));
505:         assert(!std.mem.eql(u8, field.name, "--"));
506: 
507:         var result: []const u8 = "--";
508:         var index = 0;
509:         while (std.mem.indexOfScalar(u8, field.name[index..], '_')) |i| {
510:             result = result ++ field.name[index..][0..i] ++ "-";
511:             index = index + i + 1;
512:         }
513:         result = result ++ field.name[index..];
514:         break :blk result;
515:     };
516: }
