518: test flag_name {
519:     const field = @typeInfo(struct { statsd: bool }).@"struct".fields[0];
520:     try std.testing.expectEqualStrings(flag_name(field), "--statsd");
521: }
522: 
523: fn flag_name_positional(comptime field: std.builtin.Type.StructField) []const u8 {
524:     comptime assert(std.mem.indexOfScalar(u8, field.name, '_') == null);
525:     return "<" ++ field.name ++ ">";
526: }
