528: /// Fuzz parse_flag_value function:
529: ///
530: /// - Check that ok cases return a value.
531: /// - Check that err cases return an error with a properly formatted diagnostics.
532: /// - Check that the diagnostic contains specified substring
533: /// - Random tests with the input alphabet seeded from explicit cases.
534: /// - Random tests with uniform input.
535: pub fn parse_flag_value_fuzz(
536:     comptime T: type,
537:     parse_flag_value: fn ([]const u8, *?[]const u8) error{InvalidFlagValue}!T,
538:     cases: struct {
539:         ok: []const struct { []const u8, T },
540:         err: []const struct { []const u8, []const u8 },
541:     },
542: ) !void {
543:     comptime assert(T.parse_flag_value == parse_flag_value);
544: 
545:     const test_count = 50_000;
546:     const string_size_max = 32;
547: 
548:     const gpa = std.testing.allocator;
549:     var prng = stdx.PRNG.from_seed_testing();
550: 
551:     for (cases.ok) |case| {
552:         const string, const want = case;
553:         assert(string.len > 0);
554: 
555:         var diagnostic: ?[]const u8 = null;
556:         const got = try parse_flag_value(string, &diagnostic);
557:         assert(diagnostic == null);
558:         try std.testing.expectEqual(want, got);
559:     }
560: 
561:     for (cases.err) |case| {
562:         const string, const want_message = case;
563:         assert(string.len > 0); // Empty value are rejected early.
564: 
565:         var diagnostic: ?[]const u8 = null;
566:         if (parse_flag_value(string, &diagnostic)) |value| {
567:             std.debug.print("expected an error, got value: input='{s}', value={}", .{
568:                 string,
569:                 value,
570:             });
571:             return error.TestUnexpectedResult;
572:         } else |err| switch (err) {
573:             error.InvalidFlagValue => {
574:                 try parse_flag_value_check_diagnostic(string, diagnostic);
575:                 if (stdx.cut(diagnostic.?, want_message) == null) {
576:                     std.debug.print(
577:                         "expected diagnostic to contain substring='{s}' diagnostic='{s}'",
578:                         .{ want_message, diagnostic.? },
579:                     );
580:                     return error.TestUnexpectedResult;
581:                 }
582:             },
583:         }
584:     }
585: 
586:     var corpus: std.ArrayListUnmanaged(u8) = .empty;
587:     defer corpus.deinit(gpa);
588: 
589:     for (cases.ok) |case| try corpus.appendSlice(gpa, case[0]);
590:     for (cases.err) |case| try corpus.appendSlice(gpa, case[0]);
591:     for (0..5) |_| try corpus.append(gpa, prng.int(u8));
592: 
593:     std.mem.sort(u8, corpus.items, {}, std.sort.asc(u8));
594: 
595:     const alphabet = unique(corpus.items);
596: 
597:     var string_buffer: [string_size_max]u8 = @splat(0);
598:     for (0..test_count) |_| {
599:         const string_size = prng.range_inclusive(usize, 1, string_size_max);
600:         const string = string_buffer[0..string_size];
601:         assert(string.len > 0);
602:         if (prng.boolean()) {
603:             for (string) |*c| c.* = alphabet[prng.index(alphabet)];
604:         } else {
605:             for (string) |*c| c.* = prng.int(u8);
606:         }
607: 
608:         var diagnostic: ?[]const u8 = null;
609:         if (parse_flag_value(string, &diagnostic)) |_| {
610:             assert(diagnostic == null);
611:         } else |err| switch (err) {
612:             error.InvalidFlagValue => try parse_flag_value_check_diagnostic(string, diagnostic),
613:         }
614:     }
615: }
616: 
617: fn parse_flag_value_check_diagnostic(string: []const u8, diagnostic: ?[]const u8) !void {
618:     const message = diagnostic orelse {
619:         std.debug.print("expected a diagnostic: string='{s}'", .{string});
620:         return error.TestUnexpectedResult;
621:     };
622:     if (!(message.len > 0 and
623:         std.ascii.isLower(message[0]) and
624:         message[message.len - 1] == ':'))
625:     {
626:         std.debug.print("wrong diagnostic format: string='{s}' diagnostic='{s}'", .{
627:             string,
628:             message,
629:         });
630:         return error.TestUnexpectedResult;
631:     }
632: }
633: 
634: fn unique(sorted: []u8) []u8 {
635:     assert(sorted.len > 0);
636: 
637:     var count: usize = 1;
638:     for (1..sorted.len) |index| {
639:         assert(sorted[count - 1] <= sorted[index]);
640:         if (sorted[count - 1] == sorted[index]) {
641:             // Duplicate! Skip to the next index.
642:         } else {
643:             sorted[count] = sorted[index];
644:             count += 1;
645:         }
646:     }
647: 
648:     return sorted[0..count];
649: }
