651: // CLI parsing makes a liberal use of `fatal`, so testing it within the process is impossible. We
652: // test it out of process by:
653: //   - using Zig compiler to build this very file as an executable in a temporary directory,
654: //   - running the following main with various args and capturing stdout, stderr, and the exit code.
655: //   - asserting that the captured values are correct.
656: // For production builds, don't include the main function.
657: // This is `if __name__ == "__main__":` at comptime!
658: pub const main =
659:     if (@import("root") != @This()) {} else struct {
660:         const CLIArgs = union(enum) {
661:             empty,
662:             prefix: struct {
663:                 foo: u8 = 0,
664:                 foo_bar: u8 = 0,
665:                 opt: bool = false,
666:                 option: bool = false,
667:             },
668:             positional: struct {
669:                 flag: bool = false,
670: 
671:                 @"--": void,
672:                 p1: []const u8,
673:                 p2: []const u8,
674:                 p3: ?u32 = null,
675:                 p4: ?u32 = null,
676:             },
677:             extended: struct {
678:                 flag: bool = false,
679:                 @"--": void,
680:                 rest: []const []const u8,
681:             },
682:             required: struct {
683:                 foo: u8,
684:                 bar: u8,
685:             },
686:             values: struct {
687:                 int: u32 = 0,
688:                 size: stdx.ByteSize = .{ .value = 0 },
689:                 boolean: bool = false,
690:                 path: []const u8 = "not-set",
691:                 optional: ?[]const u8 = null,
692:                 choice: enum { marlowe, shakespeare } = .marlowe,
693:             },
694:             subcommand: union(enum) {
695:                 pub const help =
696:                     \\subcommand help
697:                     \\
698:                 ;
699: 
700:                 c1: struct { a: bool = false },
701:                 c2: struct { b: bool = false },
702:             },
703: 
704:             pub const help =
705:                 \\ flags-test-program [flags]
706:                 \\
707:             ;
708:         };
709: 
710:         fn main() !void {
711:             var gpa_allocator = std.heap.GeneralPurposeAllocator(.{}){};
712:             const gpa = gpa_allocator.allocator();
713: 
714:             var flags = Flags.init(gpa);
715:             defer flags.deinit(gpa);
716: 
717:             const cli_args = flags.parse(CLIArgs);
