107:     pub fn calculate_checksum(self: *const Header) u128 {
108:         const checksum_size = @sizeOf(@TypeOf(self.checksum));
109:         assert(checksum_size == 16);
110:         const checksum_value = vsr.checksum(std.mem.asBytes(self)[checksum_size..]);
111:         assert(@TypeOf(checksum_value) == @TypeOf(self.checksum));
112:         return checksum_value;
113:     }
114: 
115:     pub fn calculate_checksum_body(self: *const Header, body: []const u8) u128 {
116:         assert(self.size == @sizeOf(Header) + body.len);
117:         const checksum_size = @sizeOf(@TypeOf(self.checksum_body));
118:         assert(checksum_size == 16);
119:         const checksum_value = vsr.checksum(body);
120:         assert(@TypeOf(checksum_value) == @TypeOf(self.checksum_body));
121:         return checksum_value;
122:     }
123: 
124:     /// This must be called only after set_checksum_body() so that checksum_body is also covered:
125:     pub fn set_checksum(self: *Header) void {
126:         self.checksum = self.calculate_checksum();
127:     }
128: 
129:     pub fn set_checksum_body(self: *Header, body: []const u8) void {
130:         self.checksum_body = self.calculate_checksum_body(body);
131:     }
132: 
133:     pub fn valid_checksum(self: *const Header) bool {
134:         return self.checksum == self.calculate_checksum();
135:     }
136: 
137:     pub fn valid_checksum_body(self: *const Header, body: []const u8) bool {
138:         return self.checksum_body == self.calculate_checksum_body(body);
139:     }
