165:     /// Returns null if all fields are set correctly according to the command, or else a warning.
166:     /// This does not verify that checksum is valid, and expects that this has already been done.
167:     pub fn invalid(self: *const Header) ?[]const u8 {
168:         if (self.checksum_padding != 0) return "checksum_padding != 0";
169:         if (self.checksum_body_padding != 0) return "checksum_body_padding != 0";
170:         if (self.nonce_reserved != 0) return "nonce_reserved != 0";
171:         if (self.size < @sizeOf(Header)) return "size < @sizeOf(Header)";
172:         if (self.size > constants.message_size_max) return "size > message_size_max";
173:         if (self.epoch != 0) return "epoch != 0";
174:         if (!stdx.zeroed(&self.reserved_frame)) return "reserved_frame != 0";
175: 
176:         if (self.command == .block) {
177:             if (self.protocol > vsr.Version) return "block: protocol > Version";
178:         } else {
179:             if (self.protocol != vsr.Version) return "protocol != Version";
180:         }
181: 
182:         switch (self.into_any()) {
183:             inline else => |command_header| return command_header.invalid_header(),
184:             // The `Command` enum is exhaustive, so we can't write an "else" branch here. An unknown
185:             // command is a possibility, but that means that someone has send us a message with
186:             // matching cluster, matching version, correct checksum, and a command we don't know
187:             // about. Ignoring unknown commands might be unsafe, so the replica intentionally
188:             // crashes here, which is guaranteed by Zig's ReleaseSafe semantics.
189:             //
190:             // _ => unreachable
191:         }
192:     }
