194:     /// Returns whether the immediate sender is a replica or client (if this can be determined).
195:     /// Some commands such as .request or .prepare may be forwarded on to other replicas so that
196:     /// Header.replica or Header.client only identifies the ultimate origin, not the latest peer.
197:     pub fn peer_type(self: *const Header) vsr.Peer {
198:         return switch (self.into_any()) {
199:             .reserved => unreachable,
200: 
201:             .reply,
202:             .prepare,
203:             .block,
204:             => .unknown,
205: 
206:             // The peer may be a replica or a client, since replicas forward request messages.
207:             // However, we return the client ID, as it is useful for the MessageBus. Specifically,
208:             // a replica that receives a request from a client can immediately cache the connection
209:             // in its client map, instead of waiting for an infrequent PingClient message to do so.
210:             .request => |request| .{ .client_likely = request.client },
211: 
212:             // The peer is certainly a client:
213:             .ping_client => |ping| .{ .client = ping.client },
214: 
215:             // The peer is certainly a replica:
216:             .ping,
217:             .pong,
218:             .pong_client,
219:             .prepare_ok,
220:             .commit,
221:             .exit_view,
222:             .join_view,
223:             .view,
224:             .request_view,
225:             .request_headers,
226:             .request_prepare,
227:             .request_reply,
228:             .headers,
229:             .eviction,
230:             .request_blocks,
231:             => .{ .replica = self.replica },
232: 
233:             .deprecated_12,
234:             .deprecated_21,
235:             .deprecated_22,
236:             .deprecated_23,
237:             => .unknown,
238:         };
239:     }
