178:     fn submit(
179:         context: *TestContext,
180:         operation: TestContext.StateMachine.Operation,
181:         input_buffer: []align(16) u8,
182:         input_size: u32,
183:         output_buffer: *align(16) [constants.message_body_size_max]u8,
184:     ) []const u8 {
185:         const message_body: []align(16) const u8 = message_body: {
186:             if (!operation.is_multi_batch()) {
187:                 break :message_body input_buffer[0..input_size];
188:             }
189:             assert(operation.is_multi_batch());
190:             const event_size = operation.event_size();
191:             var body_encoder = MultiBatchEncoder.init(input_buffer, .{
192:                 .element_size = event_size,
193:             });
194:             body_encoder.add(input_size);
195:             const bytes_written = body_encoder.finish();
196:             assert(bytes_written > 0);
197:             break :message_body input_buffer[0..bytes_written];
198:         };
199:         context.prepare(operation, message_body);
200: 
201:         const pulse_needed = context.state_machine.pulse_needed(
202:             context.state_machine.prepare_timestamp,
203:         );
204:         maybe(pulse_needed);
205:         // Pulse is executed in a best-effort manner
206:         // after committing the current pipelined operation.
207:         defer if (pulse_needed) context.pulse();
208: 
209:         const reply_actual_size = context.execute(
210:             context.op,
211:             operation,
212:             message_body,
213:             output_buffer,
214:         );
215: 
216:         if (!operation.is_multi_batch()) {
217:             return output_buffer[0..reply_actual_size];
218:         }
219:         assert(operation.is_multi_batch());
220: 
221:         const result_size = operation.result_size();
222:         var reply_decoder = MultiBatchDecoder.init(
223:             output_buffer[0..reply_actual_size],
224:             .{ .element_size = result_size },
225:         ) catch unreachable;
226:         assert(reply_decoder.batch_count() == 1);
227:         return reply_decoder.peek();
228:     }
