230:     pub fn prepare(
231:         context: *TestContext,
232:         operation: TestContext.StateMachine.Operation,
233:         message_body_used: []align(16) const u8,
234:     ) void {
235:         context.state_machine.commit_timestamp = context.state_machine.prepare_timestamp;
236:         context.state_machine.prepare_timestamp += 1;
237:         context.state_machine.prepare(
238:             operation,
239:             message_body_used,
240:         );
241:     }
