243:     fn pulse(context: *TestContext) void {
244:         if (context.state_machine.pulse_needed(context.state_machine.prepare_timestamp)) {
245:             const operation = vsr.Operation.pulse.cast(TestContext.StateMachine.Operation);
246:             context.prepare(operation, &.{});
247:             const pulse_size = context.execute(
248:                 context.op,
249:                 operation,
250:                 &.{},
251:                 undefined, // Output is never used for pulse.
252:             );
253:             assert(pulse_size == 0);
