258:     pub fn execute(
259:         context: *TestContext,
260:         op: u64,
261:         operation: TestContext.StateMachine.Operation,
262:         message_body_used: []align(16) const u8,
263:         output_buffer: *align(16) [constants.message_body_size_max]u8,
264:     ) usize {
265:         const timestamp = context.state_machine.prepare_timestamp;
266:         context.busy = true;
267:         context.state_machine.prefetch_timestamp = timestamp;
268:         context.state_machine.prefetch(
269:             TestContext.callback,
270:             op,
271:             op,
272:             operation,
273:             message_body_used,
274:         );
275:         while (context.busy) context.storage.run();
276: 
277:         return context.state_machine.commit(
278:             1,
279:             op,
280:             timestamp,
281:             operation,
282:             message_body_used,
283:             output_buffer,
284:         );
285:     }
