503: const TestGetChangeEventsResult = struct {
504:     const Balance = struct {
505:         account_id: u128,
506:         debits_pending: u128,
507:         debits_posted: u128,
508:         credits_pending: u128,
509:         credits_posted: u128,
510:         closed: ?enum { CLSD } = null,
511:     };
512: 
513:     event_type: ?enum { PEN, POS, VOI, EXP } = null,
514:     timestamp_transfer: ?u128 = null,
515:     amount: u128,
516:     transfer_pending_id: ?u128 = null,
517:     dr_account: Balance,
518:     cr_account: Balance,
519: 
520:     fn match(
521:         self: *const TestGetChangeEventsResult,
522:         accounts: *std.AutoHashMap(u128, Account),
523:         transfers: *std.AutoHashMap(u128, Transfer),
524:         event: *const ChangeEvent,
525:     ) bool {
526:         if (self.timestamp_transfer) |id| {
527:             const transfer = transfers.get(id).?;
528:             if (event.type == .two_phase_expired) return false;
529:             if (event.timestamp != transfer.timestamp) return false;
530:             if (!match_transfer(event, &transfer)) return false;
531:         }
532:         if (self.event_type) |event_type| {
533:             const expected: ChangeEventType = switch (event_type) {
534:                 .PEN => .two_phase_pending,
535:                 .POS => .two_phase_posted,
536:                 .VOI => .two_phase_voided,
537:                 .EXP => .two_phase_expired,
538:             };
539:             if (event.type != expected) return false;
540:         } else {
541:             if (event.type != .single_phase) return false;
542:         }
543:         if (event.transfer_amount != self.amount) return false;
544:         if (self.transfer_pending_id) |transfer_pending_id| {
545:             switch (event.type) {
546:                 .two_phase_pending, .single_phase => return false,
547:                 .two_phase_posted, .two_phase_voided => {
548:                     if (event.transfer_pending_id != transfer_pending_id) return false;
549:                 },
550:                 .two_phase_expired => {
551:                     const transfer = transfers.get(transfer_pending_id).?;
552:                     if (transfer.timeout == 0) return false;
553:                     if (event.timestamp <
554:                         transfer.timestamp + transfer.timeout_ns()) return false;
555:                     if (!match_transfer(event, &transfer)) return false;
556:                 },
557:             }
558:         }
559: 
560:         const dr_account = accounts.get(self.dr_account.account_id).?;
561:         if (dr_account.ledger != event.ledger) return false;
562:         if (self.dr_account.account_id != event.debit_account_id) return false;
563:         if (dr_account.timestamp != event.debit_account_timestamp) return false;
564:         if (self.dr_account.debits_pending != event.debit_account_debits_pending) return false;
565:         if (self.dr_account.debits_posted != event.debit_account_debits_posted) return false;
566:         if (self.dr_account.credits_pending != event.debit_account_credits_pending) return false;
567:         if (self.dr_account.credits_posted != event.debit_account_credits_posted) return false;
568:         if ((self.dr_account.closed == .CLSD) != event.debit_account_flags.closed) return false;
569: 
570:         const cr_account = accounts.get(self.cr_account.account_id).?;
571:         if (cr_account.ledger != event.ledger) return false;
572:         if (self.cr_account.account_id != event.credit_account_id) return false;
573:         if (cr_account.timestamp != event.credit_account_timestamp) return false;
574:         if (self.cr_account.debits_pending != event.credit_account_debits_pending) return false;
575:         if (self.cr_account.debits_posted != event.credit_account_debits_posted) return false;
576:         if (self.cr_account.credits_pending != event.credit_account_credits_pending) return false;
577:         if (self.cr_account.credits_posted != event.credit_account_credits_posted) return false;
578:         if ((self.cr_account.closed == .CLSD) != event.credit_account_flags.closed) return false;
579: 
580:         return true;
581:     }
582: 
583:     fn match_transfer(event: *const ChangeEvent, transfer: *const tb.Transfer) bool {
584:         if (event.transfer_timestamp != transfer.timestamp) return false;
585:         if (event.transfer_id != transfer.id) return false;
586:         if (event.transfer_amount != transfer.amount and
587:             // The in-memory model keeps the `AMOUNT_MAX`.
588:             transfer.amount != std.math.maxInt(u128)) return false;
589:         if (event.transfer_pending_id != transfer.pending_id) return false;
590:         if (event.transfer_user_data_128 != transfer.user_data_128) return false;
591:         if (event.transfer_user_data_64 != transfer.user_data_64) return false;
592:         if (event.transfer_user_data_32 != transfer.user_data_32) return false;
593:         if (event.transfer_code != transfer.code) return false;
594:         if (event.ledger != transfer.ledger) return false;
595:         if (event.ledger != transfer.ledger) return false;
596:         if (@as(u16, @bitCast(transfer.flags)) !=
597:             @as(u16, @bitCast(event.transfer_flags))) return false;
598:         return true;
599:     }
600: };
