608: fn check(test_table: []const u8) !void {
609:     const parse_table = @import("testing/table.zig").parse;
610:     const test_actions = parse_table(TestAction, test_table);
611: 
612:     // Runs the same test for each variation of supported operations,
613:     // simulating different client versions.
614:     for (TestContext.Operation.versions) |*version_map| {
615:         try check_version(
616:             test_actions.const_slice(),
617:             version_map,
618:         );
619:     }
620: }
621: 
622: fn check_version(
623:     test_actions: []const TestAction,
624:     version_map: *const TestContext.Operation.VersionMap,
625: ) !void {
626:     const allocator = std.testing.allocator;
627: 
628:     var context: TestContext = undefined;
629:     try context.init(allocator);
630:     defer context.deinit(allocator);
631: 
632:     var accounts = std.AutoHashMap(u128, Account).init(allocator);
633:     defer accounts.deinit();
634: 
635:     var transfers = std.AutoHashMap(u128, Transfer).init(allocator);
636:     defer transfers.deinit();
637: 
638:     // The result code `.exists` always returns the timestamp of the original event.
639:     // Even if the existing event was created within a linked chain and rolled back.
640:     // For example, the linked chain:
641:     //  events:  { id=1, flags=linked; id=1 }
642:     //  results: { result=linked_event_failed, timestamp=100; result=exists, timestamp=100 }
643:     //                                                   ^^^                           ^^^
644:     var linked_events_failed = std.AutoHashMap(u128, u64).init(allocator);
645:     defer linked_events_failed.deinit();
646: 
647:     var request = std.ArrayListAligned(u8, 16).init(allocator);
648:     defer request.deinit();
649: 
650:     try request.ensureTotalCapacity(constants.message_body_size_max);

650:     try request.ensureTotalCapacity(constants.message_body_size_max);
651: 
652:     var reply = std.ArrayListAligned(u8, 16).init(allocator);
653:     defer reply.deinit();
654: 
655:     var operation: ?TestContext.Operation = null;
656:     for (test_actions) |test_action| {
657:         switch (test_action) {
658:             .setup => |b| {
659:                 assert(operation == null);
660: 
661:                 const account = context.get_account_from_cache(b.account).?;
662:                 var account_new = account;
663: 
664:                 account_new.debits_pending = b.debits_pending;
665:                 account_new.debits_posted = b.debits_posted;
666:                 account_new.credits_pending = b.credits_pending;
667:                 account_new.credits_posted = b.credits_posted;
668:                 assert(!account_new.debits_exceed_credits(0));
669:                 assert(!account_new.credits_exceed_debits(0));
670: 
671:                 if (!stdx.equal_bytes(Account, &account_new, &account)) {
672:                     context.state_machine.forest.grooves.accounts.update(.{
673:                         .old = &account,
674:                         .new = &account_new,
675:                     });
676:                 }
677:             },
678:             .tick => |ticks| {
679:                 assert(ticks.value != 0);
680: 
681:                 const interval_ns: u64 = @abs(ticks.value) *
682:                     @as(u64, switch (ticks.unit) {
683:                         .nanoseconds => 1,
684:                         .seconds => std.time.ns_per_s,
685:                     });
686: 
687:                 // The `parse` logic already computes `maxInt - value` when a unsigned int is
688:                 // represented as a negative number. However, we need to use a signed int and
689:                 // perform our own calculation to account for the unit.
690:                 context.state_machine.prepare_timestamp += if (ticks.value > 0)
691:                     interval_ns
692:                 else
693:                     TimestampRange.timestamp_max - interval_ns;
694: 
695:                 // Pulse is executed when the cluster is idle.
696:                 context.pulse();
697:             },
698:             .account => |a| {
699:                 assert(operation == null or operation.? == .create_accounts);
700:                 operation = .create_accounts;
701: 
702:                 var event = a.event();
703:                 try request.appendSlice(std.mem.asBytes(&event));
704: 
705:                 const timestamp_commit = context.state_machine.prepare_timestamp + 1 +
706:                     @divExact(request.items.len, @sizeOf(Account));
707:                 if (event.timestamp == 0) event.timestamp = timestamp_commit;
708:                 if (a.status == .created) {
709:                     try accounts.put(a.id, event);
710:                 }
711: 
712:                 switch (version_map.get(.create_accounts)) {
713:                     .create_accounts => {
714:                         const result = CreateAccountResult{
715:                             .timestamp = timestamp_expected: {
716:                                 if (a.status == .created or a.status == .linked_event_failed) {
717:                                     break :timestamp_expected event.timestamp;
718:                                 }
719:                                 if (a.status == .exists) {
720:                                     break :timestamp_expected if (accounts.get(a.id)) |exists|
721:                                         exists.timestamp
722:                                     else
723:                                         linked_events_failed.get(a.id).?;
724:                                 }
725:                                 break :timestamp_expected timestamp_commit;
726:                             },
727:                             .status = a.status,
728:                         };
729:                         try reply.appendSlice(std.mem.asBytes(&result));
730: 
731:                         if (event.flags.linked) {
732:                             if (a.status == .linked_event_failed) {
733:                                 try linked_events_failed.putNoClobber(event.id, event.timestamp);
734:                             }
735:                         } else {
736:                             linked_events_failed.clearRetainingCapacity();
737:                         }
738:                     },
739:                     .deprecated_create_accounts_sparse,
740:                     .deprecated_create_accounts_unbatched,
741:                     => if (a.status != .created) {
742:                         const result = tb.CreateAccountErrorResult{
743:                             .index = @intCast(@divExact(request.items.len, @sizeOf(Account)) - 1),
744:                             .result = a.status,
745:                         };
746:                         try reply.appendSlice(std.mem.asBytes(&result));
747:                     },
748:                     else => unreachable,
749:                 }
750:             },
751:             .transfer => |t| {
752:                 assert(operation == null or operation.? == .create_transfers);
753:                 operation = .create_transfers;
754: 
755:                 var event = t.event();
756:                 try request.appendSlice(std.mem.asBytes(&event));
757: 
758:                 const timestamp_commit = context.state_machine.prepare_timestamp + 1 +
759:                     @divExact(request.items.len, @sizeOf(Transfer));
760:                 if (t.timestamp == 0) event.timestamp = timestamp_commit;
761:                 if (t.status == .created) {
762:                     if (event.pending_id != 0) {
763:                         // Fill in default values.
764:                         const t_pending = transfers.get(event.pending_id).?;
765:                         inline for (.{
766:                             "debit_account_id",
767:                             "credit_account_id",
768:                             "ledger",
769:                             "code",
770:                             "user_data_128",
771:                             "user_data_64",
772:                             "user_data_32",
773:                         }) |field| {
774:                             if (@field(event, field) == 0) {
775:                                 @field(event, field) = @field(t_pending, field);
776:                             }
777:                         }
778: 
779:                         if (event.flags.void_pending_transfer) {
780:                             if (event.amount == 0) event.amount = t_pending.amount;
781:                         }
782:                     }
783:                     try transfers.put(t.id, event);
784:                 }
785: 
786:                 switch (version_map.get(.create_transfers)) {
787:                     .create_transfers => {
788:                         const result: CreateTransferResult = .{
789:                             .timestamp = timestamp_expected: {
790:                                 if (t.status == .created or t.status == .linked_event_failed) {
791:                                     break :timestamp_expected event.timestamp;
792:                                 }
793:                                 if (t.status == .exists) {
794:                                     break :timestamp_expected if (transfers.get(t.id)) |exists|
795:                                         exists.timestamp
796:                                     else
797:                                         linked_events_failed.get(t.id).?;
798:                                 }
799:                                 break :timestamp_expected timestamp_commit;
800:                             },
801:                             .status = t.status,
802:                         };
803:                         try reply.appendSlice(std.mem.asBytes(&result));
804: 
805:                         if (event.flags.linked) {
806:                             if (t.status == .linked_event_failed) {
807:                                 try linked_events_failed.putNoClobber(event.id, event.timestamp);
808:                             }
809:                         } else {
810:                             linked_events_failed.clearRetainingCapacity();
811:                         }
812:                     },
813:                     .deprecated_create_transfers_sparse,
814:                     .deprecated_create_transfers_unbatched,
815:                     => if (t.status != .created) {
816:                         const result: tb.CreateTransferErrorResult = .{
817:                             .index = @intCast(@divExact(request.items.len, @sizeOf(Transfer)) - 1),
818:                             .result = t.status,
819:                         };
820:                         try reply.appendSlice(std.mem.asBytes(&result));
821:                     },
822:                     else => unreachable,
823:                 }
824:             },
825:             .lookup_account => |a| {
826:                 assert(operation == null or operation.? == .lookup_accounts);
827:                 operation = .lookup_accounts;
828: 
829:                 try request.appendSlice(std.mem.asBytes(&a.id));
