954:         for (ArgsStruct.fields, 0..) |field, index| {
955:             const arg_worst_case = switch (field.type) {
956:                 u8, u16, u32, u64, u128 => std.math.maxInt(field.type),
957:                 else => @compileError("array_print: unsupported type: " ++ @typeName(field.type)),
