5: const Diacritic = enum(u8) {
6:     empty, // nguyên âm, không dấu.
7:     circumflex, // dấu nón: â, ô, ê.
8:     horn, // dấu móc: ư, ơ.
9:     breve, // dấu ă.
10:     bar, // dấu gạch: đ.
11: };
12: 
13: const Tone = enum(u8) {
14:     level, // thanh ngang, không dấu.
15:     rising, // sắc.
16:     falling, // huyền.
17:     dipping_rising, // hỏi.
18:     rising_glottalized, // ngã.
19:     falling_glottalized, // nặng.
20: };
21: 
22: const Span = extern struct {
23:     // Alphabet ASCII character, could be lowercase or uppercase.
24:     base: u8,
25:     // By default, it's plain alphabet character.
26:     diacritic: Diacritic = .empty,
27:     // By default, no tone is placed.
28:     tone: Tone = .level,
29: 
30:     // Create a Span with plain alphabet character, no diacritic, no tone.
31:     pub fn init(base: u8) Span {
32:         // Only allow a-zA-Z.
33:         assert(std.ascii.isAlphabetic(base));
34:         return .{ .base = base };
35:     }
36: 
37:     // Create a Span with diacritic, no tone.
38:     pub fn init_diacritic(base: u8, diacritic: Diacritic) Span {
39:         // Only allow a-zA-Z.
40:         assert(std.ascii.isAlphabetic(base));
41: 
42:         // Only allow a valid Vietnamese alphabet combinations.
43:         switch (diacritic) {
44:             // All alphabet is allowed without diacritic.
45:             .empty => {},
46:             // Only a, o, e are valid with circumflex.
47:             .circumflex =>
48:                 switch (base) {
49:                     'A', 'O', 'E', 'a', 'o', 'e' => {},
50:                     else => unreachable
51:                 },
52:             // Only u, o are valid with horn.
53:             .horn => switch (base) {
54:                 'U', 'O', 'u', 'o' => {},
55:                 else => unreachable
56:             },
57:             // Only a is valid with breve.
58:             .breve => switch (base) {
59:                 'A', 'a' => {},
60:                 else => unreachable
61:             },
62:             // Only d is valid with bar.
63:             .bar => switch (base) {
64:                 'D', 'd' => {},
65:                 else => unreachable
66:             }
67:         }
68:         return .{ .base = base, .diacritic = diacritic };
69:     }
70: };
