97:     const chars = .{
98:         .{ .base = 'A', .diacritic = .breve }, // Ă.
99:         .{ .base = 'a', .diacritic = .breve }, // ă.
100:         .{ .base = 'A', .diacritic = .circumflex }, // Â.
101:         .{ .base = 'a', .diacritic = .circumflex }, // â.
102:         .{ .base = 'E', .diacritic = .circumflex }, // Ê.
103:         .{ .base = 'e', .diacritic = .circumflex }, // ê.
104:         .{ .base = 'O', .diacritic = .circumflex }, // Ô.
105:         .{ .base = 'o', .diacritic = .circumflex }, // ô.
106:         .{ .base = 'O', .diacritic = .horn }, // Ơ.
107:         .{ .base = 'o', .diacritic = .horn }, // ơ.
108:         .{ .base = 'U', .diacritic = .horn }, // Ư.
109:         .{ .base = 'u', .diacritic = .horn }, // ư.
110:         .{ .base = 'D', .diacritic = .bar }, // Đ.
111:         .{ .base = 'd', .diacritic = .bar }, // đ.
112:     };
113: 
114:     // Need `inline for` to know the tuple at comptime.
115:     inline for (chars) |c| {
116:         // Act
117:         const sp = Span.init_diacritic(c.base, c.diacritic);
118: 
119:         // Assert
120:         try expectEqual(c.base, sp.base);
121:         try expectEqual(c.diacritic, sp.diacritic);
122:         try expectEqual(Tone.level, sp.tone);
123:     }
124: }
