133: const State = extern struct {
134:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
135:     // longer than 16.
136:     buffer_effective: [16]Span,
137:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
138:     // value (256), we will reset the effective buffer and this value.
139:     buffer_length: u8,
140:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
141:     // switch, input cancellation, exceed effective buffer). This value is independent from mode and
142:     // has higher priority, e.g. if the mode is `telex` but the engine is working on position on or
143:     // after literal index, the engine will skip Vietnamese input processing (we only count positive
144:     // value, -1 mean no literal index).
145:     literal_start_index: i8,
146:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
147:     mode: InputMode = InputMode.literal,
148: };
